import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";

const TeacherDashboard = () => {
  const [darkMode] = useState(false);
  const [subjects, setSubjects] = useState([]);
  const [error, setError] = useState('');
  const username = localStorage.getItem('username');
  const token = localStorage.getItem('accessToken');

  useEffect(() => {
    fetch('http://localhost:8000/api/teacher-subjects/', {
      headers: {
        Authorization: `Bearer ${token}`,
      },
    })
      .then(res => res.json())
      .then(data => {
        if (Array.isArray(data)) {
          setSubjects(data);
        } else {
          setError('Error loading subjects.');
        }
      })
      .catch(() => setError('Failed to fetch subjects.'));
  }, []);

  return (
    <div className={`container-fluid min-vh-100 py-5 ${darkMode ? 'bg-dark text-light' : 'bg-light text-dark'}`}>
      <div className="container">
        <div className="d-flex justify-content-between align-items-center mb-4">
          <h2>👨‍🏫 Teacher Dashboard</h2>
          <Link to="/profile" className="btn btn-secondary fw-bold">Hi, {username} 👋</Link>
        </div>

        <h4 className="text-center mb-5">Welcome back, <span className="text-tertiary">{username}</span></h4>

        {error && <p className="text-danger">{error}</p>}

        <div className="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
          <div className="col">
            <div className="card bg-primary text-white h-100 shadow">
              <div className="card-body text-center">
                <h5 className="card-title">📘 My Subjects</h5>
                {subjects.length === 0 ? (
                  <p className="card-text">No subjects assigned.</p>
                ) : (
                  <ul className="list-unstyled">
                    {subjects.map((subj, i) => (
                      <li key={i}>{subj.name} ({subj.classroom})</li>
                    ))}
                  </ul>
                )}
              </div>
            </div>
          </div>

          {/* Reuse existing cards if needed */}
          <div className="col">
            <Link to="/attendance" className="text-decoration-none">
              <div className="card bg-warning text-dark h-100 shadow">
                <div className="card-body text-center">
                  <h5 className="card-title">✅ Attendance</h5>
                  <p className="card-text">Track student attendance.</p>
                </div>
              </div>
            </Link>
          </div>

          <div className="col">
            <Link to="/grades" className="text-decoration-none">
              <div className={`card h-100 shadow ${darkMode ? 'bg-light text-dark' : 'bg-dark text-light border border-light'}`}>
                <div className="card-body text-center">
                  <h5 className="card-title">🏅 Grades</h5>
                  <p className="card-text">View and submit grades.</p>
                </div>
              </div>
            </Link>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TeacherDashboard;
